#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor gemm_relu_divide_impl_npu(const at::Tensor& x,
                                     const at::Tensor& w,
                                     const at::Tensor& b,
                                     const at::Tensor& divisor) {
    TORCH_CHECK(divisor.numel() == 1, \"divisor must be a scalar tensor on NPU\");
    auto M = x.size(0);
    auto Kx = x.size(1);
    TORCH_CHECK(w.size(1) == Kx, \"W's in_features must equal x's dim1\");
    auto N = w.size(0);
    at::Tensor y = at::empty({M, N}, x.options());
    EXEC_NPU_CMD(aclnnGemmReluDivideCustom, x, w, b, divisor, y);
    return y;
}

